import React, { useState, useEffect, useRef } from 'react';
import { useMusic } from '../context/MusicContext';
import { Play, Pause, SkipBack, SkipForward, ListPlus, Plus, Music } from 'lucide-react';
import axios from 'axios';

const GlobalPlayer = () => {
  const { currentSong, isPlaying, setIsPlaying, audioRef, togglePlay, handleNext, handlePrev } = useMusic();
  const [progress, setProgress] = useState(0);
  
  // State quản lý Menu Playlist
  const [showMenu, setShowMenu] = useState(false);
  const [userPlaylists, setUserPlaylists] = useState([]);
  const menuRef = useRef(null);

  const user = JSON.parse(localStorage.getItem('user'));

  // Đóng menu khi click ra ngoài
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (menuRef.current && !menuRef.current.contains(event.target)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Lấy danh sách playlist của User
  const fetchPlaylists = async () => {
    if (!user) return;
    try {
      const res = await axios.get(`http://localhost:5000/api/songs/playlists/user/${user._id}`);
      setUserPlaylists(res.data);
      setShowMenu(!showMenu); // Bật/Tắt menu
    } catch (err) {
      console.error("Lỗi lấy playlist:", err);
    }
  };

  // 1. Hàm tạo Playlist mới (với bài hiện tại)
  const handleCreateNew = async () => {
    const name = prompt("Tên Playlist mới:");
    if (!name) return;
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title: name,
        userId: user._id,
        songIds: [currentSong._id]
      });
      alert("Đã tạo và thêm bài hát thành công!");
      setShowMenu(false);
    } catch (err) { alert("Lỗi khi tạo playlist"); }
  };

  // 2. Hàm thêm vào Playlist đã có
  const handleAddToExisting = async (playlistId) => {
    try {
      // Lưu ý: Route này bạn cần đảm bảo Backend có hỗ trợ cập nhật mảng songs
      await axios.put(`http://localhost:5000/api/songs/playlists/${playlistId}`, {
        songId: currentSong._id 
      });
      alert("Đã thêm vào playlist!");
      setShowMenu(false);
    } catch (err) { alert("Lỗi: Bài hát có thể đã tồn tại trong playlist"); }
  };

  // ... (giữ nguyên các hàm onTimeUpdate, handleSeek, formatTime cũ)
  const onTimeUpdate = () => {
    const current = audioRef.current.currentTime;
    const total = audioRef.current.duration;
    setProgress((current / total) * 100 || 0);
  };

  const handleSeek = (e) => {
    const seekTime = (e.target.value / 100) * audioRef.current.duration;
    audioRef.current.currentTime = seekTime;
    setProgress(e.target.value);
  };

  const formatTime = (time) => {
    if (isNaN(time)) return "0:00";
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  if (!currentSong) return null;

  return (
    <div style={playerContainer}>
      {/* 1. Info */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '15px', width: '300px' }}>
        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={playerImg} alt="" />
        <div style={{ overflow: 'hidden' }}>
          <div style={{ fontWeight: 'bold', whiteSpace: 'nowrap', textOverflow: 'ellipsis', overflow: 'hidden' }}>{currentSong.title}</div>
          <div style={{ fontSize: '13px', color: '#888' }}>{currentSong.artist}</div>
        </div>
      </div>

      {/* 2. Controls */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '25px' }}>
          <SkipBack size={24} style={{ cursor: 'pointer' }} onClick={handlePrev} />
          <button onClick={togglePlay} style={mainPlayBtn}>
            {isPlaying ? <Pause size={28} fill="white" /> : <Play size={28} fill="white" style={{marginLeft: '4px'}} />}
          </button>
          <SkipForward size={24} style={{ cursor: 'pointer' }} onClick={handleNext} />
        </div>
        <div style={{ display: 'flex', alignItems: 'center', width: '100%', maxWidth: '600px', gap: '12px' }}>
          <span style={timeText}>{formatTime(audioRef.current?.currentTime)}</span>
          <input type="range" min="0" max="100" value={progress} onChange={handleSeek} style={progressSlider} />
          <span style={timeText}>{formatTime(audioRef.current?.duration)}</span>
        </div>
      </div>

      {/* 3. Playlist Menu Button */}
      <div style={{ width: '300px', display: 'flex', justifyContent: 'flex-end', position: 'relative' }} ref={menuRef}>
        <button onClick={fetchPlaylists} style={addPlaylistBtn}>
          <ListPlus size={20} />
          <span>Thêm vào Playlist</span>
        </button>

        {/* Menu thả nổi (Popup) */}
        {showMenu && (
          <div style={dropdownMenu}>
            <div style={menuHeader}>Lưu vào playlist</div>
            <div style={scrollArea}>
              {userPlaylists.map(pl => (
                <div key={pl._id} style={menuItem} onClick={() => handleAddToExisting(pl._id)}>
                  <Music size={16} color="#888" />
                  <span>{pl.title}</span>
                </div>
              ))}
            </div>
            <div style={{...menuItem, borderTop: '1px solid #eee', color: '#1db954'}} onClick={handleCreateNew}>
              <Plus size={18} />
              <strong>Tạo playlist mới</strong>
            </div>
          </div>
        )}
      </div>

      <audio 
        ref={audioRef} 
        src={`http://localhost:5000${currentSong.songUrl}`} 
        onTimeUpdate={onTimeUpdate}
        onEnded={handleNext}
      />
    </div>
  );
};

/* Styles */
const playerContainer = { position: 'fixed', bottom: 0, left: 0, right: 0, background: '#fff', borderTop: '1px solid #eee', padding: '15px 60px', display: 'flex', alignItems: 'center', zIndex: 9999 };
const playerImg = { width: '55px', height: '55px', borderRadius: '8px', objectFit: 'cover' };
const mainPlayBtn = { background: '#1db954', color: 'white', border: 'none', width: '50px', height: '50px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const progressSlider = { flex: 1, accentColor: '#1db954', height: '4px', cursor: 'pointer' };
const timeText = { fontSize: '11px', color: '#666' };
const addPlaylistBtn = { display: 'flex', alignItems: 'center', gap: '8px', background: '#f4f4f4', border: 'none', padding: '10px 15px', borderRadius: '20px', cursor: 'pointer', fontWeight: '500' };

// Style cho Menu Dropdown
const dropdownMenu = {
  position: 'absolute', bottom: '70px', right: '0', width: '250px', 
  background: '#fff', borderRadius: '12px', boxShadow: '0 10px 25px rgba(0,0,0,0.15)',
  padding: '10px 0', border: '1px solid #eee', textAlign: 'left'
};
const menuHeader = { padding: '10px 20px', fontSize: '14px', fontWeight: 'bold', borderBottom: '1px solid #eee' };
const scrollArea = { maxHeight: '200px', overflowY: 'auto' };
const menuItem = { 
  padding: '12px 20px', display: 'flex', alignItems: 'center', gap: '12px', 
  cursor: 'pointer', transition: '0.2s', fontSize: '14px' 
};
// Lưu ý: CSS hover không viết trực tiếp vào inline style được, bạn có thể dùng className hoặc handle mouseOver.

export default GlobalPlayer;
